sql:
SELECT event_id
FROM events
WHERE event_status = 'ongoing' AND created_by = 0;

SELECT survey_id, event_id, survey_question, survey_answer 
FROM event_surveys 
WHERE survey_question = 'How was the event?';

SELECT DISTINCT *
FROM event_surveys
WHERE event_id = 1;

SELECT DISTINCT e.title
FROM events e
INNER JOIN event_dependencies ed ON e.event_id = ed.dependent_event_id;

SELECT COUNT(event_id) AS recurring_event_count
FROM event_recurring
WHERE created_by = 0;

SELECT task_name
FROM event_tasks
WHERE priority = 'high' AND due_date > date('now');
